const { BING_MAPS_API_KEY } = appConfig

/**
 * For GDPR legal compliance regarding cookies, we need to run the Bing map in cookie free mode.
 * This can be done by using `sdk.virtualearth.net` instead of `www.bing.com` as the map API base URL.
 *
 * When tested at the end of 2025, Google and Azure maps do not have the same issue and are already compliant when it comes to cookies.
 *
 * To check what cookies are being set you can open the browser dev tools, go to the Network tab, click on the search icon at the top,
 * and search for "set-cookie".  This will filter requests that have the "set-cookie" header in the response.
 *
 * See:
 * - https://blogs.bing.com/maps/December-2005/v1-Applications-not-Referencing-dev-virtualearth
 * - https://learn.microsoft.com/en-us/bingmaps/v8-web-control/creating-and-hosting-map-controls/creating-a-basic-map-control#code-try-3
 * - https://icseng.atlassian.net/browse/EURONA-2080
 */
const MAP_API_BASE_URL = 'https://sdk.virtualearth.net/maps/sdk/mapcontrol'
const LARGEST_MARKER_SIZE_PX = 64
const BOUNDS_CHANGED_THROTTLE_DELAY_MS = 300
const WHEEL_ZOOM_DEBOUNCE_DELAY_MS = 15
const WHEEL_ZOOM_THRESHOLD = 25
const MIN_ZOOM_LEVEL = 1
const MAX_ZOOM_LEVEL = 18
const SCROLL_INSTRUCTIONS_TIMEOUT_MS = 2000
const DOUBLE_CLICK_DELAY = 250

