function createElementIfNeeded({ ref }) {
  if (!ref.current) {
    ref.current = document.createElement('div')
  }
}

function normalizeZoomLevels({ bounds, minZoom, maxZoom }) {
  // Ensure minZoom is always less than maxZoom
  // Subtract one to ensure consistency with Google Maps zoom levels.
  let normalizedMinZoom = typeof maxZoom === 'number' ? minZoom - 1 : minZoom
  let normalizedMaxZoom = maxZoom

  if (bounds) {
    normalizedMinZoom = null
    normalizedMaxZoom = null
  }

  if (typeof minZoom === 'number' && typeof maxZoom === 'number' && minZoom >= maxZoom) {
    normalizedMinZoom = maxZoom - 1
    normalizedMaxZoom = maxZoom
  }

  if (typeof normalizedMinZoom === 'number' && normalizedMinZoom <= 0) {
    normalizedMinZoom = MIN_ZOOM_LEVEL
  }

  if (typeof normalizedMaxZoom === 'number' && normalizedMaxZoom > MAX_ZOOM_LEVEL) {
    normalizedMaxZoom = MAX_ZOOM_LEVEL
  }

  return { normalizedMinZoom, normalizedMaxZoom }
}

function getMapLanguage({ shouldUseBing }) {
  // https://learn.microsoft.com/en-us/bing/search-apis/bing-image-search/reference/market-codes#bing-supported-language-codes
  // Bing doesn't support `zh` but it does support `zh-hant`.  Let's convert FamilySearch `zh` to to Bing's `zh-hant`.
  let language = i18n.language === 'zh' ? 'zh-hant' : i18n.language

  // The Bing Maps API uses 'nb' instead of 'no' for Norwegian Bokmål.
  // Let's convert FamilySearch 'no' to Bing's 'nb'.
  language = language === 'no' ? 'nb' : language

  // NOTE: Bing Maps does not support 'zh-hant' within mainland china.
  // Override the language and use 'zh-hans' instead.
  if (language === 'zh-hant' && shouldUseBing) {
    language = 'zh-hans'
  }

  return language
}

function createTouchHandlers({ mapContainer, newMap, nonInteractiveRef, setShowScrollInstructions }) {
  let isTouchstart = false
  let pageX = 0
  let pageY = 0
  let scale = 1
  let scrollInstructionsTimeout

  const touchstartHandler = (event) => {
    clearTimeout(scrollInstructionsTimeout)

    if (event.touches.length <= 1 && event.target.parentElement.classList.contains('ms-composite')) {
      pageX = event.changedTouches[0].pageX
      pageY = event.changedTouches[0].pageY
      isTouchstart = true
      newMap.setOptions({ disablePanning: true })
    } else if (event.touches.length > 1 && event.target.parentElement.classList.contains('ms-composite')) {
      event.preventDefault()
      event.stopImmediatePropagation()
      event.stopPropagation()
      setShowScrollInstructions(false)
      isTouchstart = false
      newMap.setOptions({ disablePanning: nonInteractiveRef.current })
    }

    scrollInstructionsTimeout = setTimeout(() => {
      if (!isTouchstart) {
        newMap.setOptions({ disablePanning: nonInteractiveRef.current })
        setShowScrollInstructions(false)
      }
    }, SCROLL_INSTRUCTIONS_TIMEOUT_MS)
  }

  const touchmoveHandler = (event) => {
    // Check if a second finger was added during move
    if (event.touches.length > 1 && isTouchstart) {
      // Transition from single-finger to two-finger mode
      isTouchstart = false
      clearTimeout(scrollInstructionsTimeout)
      setShowScrollInstructions(false)
      newMap.setOptions({ disablePanning: nonInteractiveRef.current })
      return
    }

    if (isTouchstart) {
      setShowScrollInstructions(true)

      const px = pageX - event.changedTouches[0].clientX
      const py = pageY - event.changedTouches[0].clientY

      if (scale === event.scale) {
        event.stopImmediatePropagation()
        event.preventDefault()
      }

      scale = event.scale

      // Find the scrollable parent container (could be window or an overlay)
      let scrollableParent = mapContainer
      while (scrollableParent && scrollableParent !== document.body) {
        const computedStyle = window.getComputedStyle(scrollableParent)
        const overflow = computedStyle.overflow
        const overflowY = computedStyle.overflowY
        const isScrollable =
          overflow === 'auto' || overflow === 'scroll' || overflowY === 'auto' || overflowY === 'scroll'

        // Check if element is actually scrollable (has overflow content)
        if (isScrollable && scrollableParent.scrollHeight > scrollableParent.clientHeight) {
          break
        }

        // Also check if element has a data-scrollable attribute
        if ('scrollable' in scrollableParent.dataset) {
          break
        }

        scrollableParent = scrollableParent.parentElement
      }

      // If no scrollable parent found, use window
      if (!scrollableParent || scrollableParent === document.body) {
        if (window.scrollY === 0) {
          window.parent.scrollBy(px, py)
        } else {
          window.scrollTo(px, py)
        }
      } else {
        // Scroll the container element
        scrollableParent.scrollBy(px, py)
      }
    }
  }

  const touchendHandler = () => {
    clearTimeout(scrollInstructionsTimeout)
    isTouchstart = false

    scrollInstructionsTimeout = setTimeout(() => {
      setShowScrollInstructions(false)
      newMap.setOptions({ disablePanning: nonInteractiveRef.current })
    }, SCROLL_INSTRUCTIONS_TIMEOUT_MS)
  }

  const cleanup = () => {
    clearTimeout(scrollInstructionsTimeout)
  }

  return { touchstartHandler, touchmoveHandler, touchendHandler, cleanup }
}

function createWheelHandler({
  ctrlKeydownRef,
  newMap,
  nonInteractiveRef,
  parentScrollsRef,
  wheelDeltaAccumulatorRef,
  wheelZoomDebounceTimeoutRef,
}) {
  return (event) => {
    if (!nonInteractiveRef.current && parentScrollsRef.current && ctrlKeydownRef.current) {
      event.preventDefault()

      // Accumulate wheel delta
      wheelDeltaAccumulatorRef.current += event.wheelDelta

      // Clear existing timeout
      if (wheelZoomDebounceTimeoutRef.current) {
        clearTimeout(wheelZoomDebounceTimeoutRef.current)
      }

      // Set new timeout
      wheelZoomDebounceTimeoutRef.current = setTimeout(() => {
        const totalDelta = wheelDeltaAccumulatorRef.current

        // Only zoom if delta exceeds threshold
        if (Math.abs(totalDelta) >= WHEEL_ZOOM_THRESHOLD) {
          let zoom = newMap.getZoom()

          if (totalDelta > 0) {
            zoom++
          } else {
            zoom--
          }

          // Make sure the zoom level value is a valid zoom level.
          if (zoom <= 0) {
            zoom = MIN_ZOOM_LEVEL
          } else if (zoom >= MAX_ZOOM_LEVEL) {
            zoom = MAX_ZOOM_LEVEL
          }

          // Set the zoom level of the map.
          newMap.setView({ zoom })
        }

        // Reset accumulator
        wheelDeltaAccumulatorRef.current = 0
      }, WHEEL_ZOOM_DEBOUNCE_DELAY_MS)
    }
  }
}

function setupMapControls({ fullscreenControlRef, mapTypeControlRef, resetViewControlRef, userLocationControlRef }) {
  const nav = document.querySelector('#MicrosoftNav')

  if (nav?.insertAdjacentElement) {
    nav.insertAdjacentElement('beforebegin', mapTypeControlRef.current)
    nav.insertAdjacentElement('beforebegin', userLocationControlRef.current)
    nav.insertAdjacentElement('beforebegin', resetViewControlRef.current)
    nav.insertAdjacentElement('afterend', fullscreenControlRef.current)

    // Remove elements to prevent A11Y errors.
    const elementsToRemove = [
      '.NavBar_MapTypeButtonContainerWrapper',
      '.bm_LocateMeControl',
      '#RadialMenu',
      '.birdseyeV2InfoExitControl',
      '#RotateButtonContainer',
    ]

    elementsToRemove.forEach((selector) => {
      const element = nav.querySelector(selector)
      if (element) {
        element.remove()
      }
    })

    // Create dummy Birdseye V2 controls to prevent SDK errors
    // The Bing Maps SDK tries to access these controls even when disableBirdseye is true
    if (!nav.querySelector('.be2LabelToggleContainer')) {
      const dummyLabelToggle = document.createElement('div')
      dummyLabelToggle.className = 'be2LabelToggleContainer' // normally a child of '.birdseyeV2InfoExitControl'
      dummyLabelToggle.style.display = 'none'
      dummyLabelToggle.style.visibility = 'hidden'
      dummyLabelToggle.style.pointerEvents = 'none'
      dummyLabelToggle.setAttribute('aria-hidden', 'true')
      nav.appendChild(dummyLabelToggle)
    }
  }
}

function createMapOptions({
  bounds,
  initialLatitude,
  initialLongitude,
  initialMapTypeId,
  initialZoom,
  maxZoom,
  minZoom,
  nonInteractive,
  parentScrolls,
}) {
  // Zoom normalization here so it's calculated fresh each time
  const { normalizedMinZoom, normalizedMaxZoom } = normalizeZoomLevels({ bounds, minZoom, maxZoom })

  return {
    backgroundColor: rawDayColors.gray['00'],
    center: {
      latitude: initialLatitude,
      longitude: initialLongitude,
    },
    disableBirdseye: true,
    disableKeyboardInput: nonInteractive,
    disablePanning: nonInteractive,
    disableScrollWheelZoom: nonInteractive || parentScrolls,
    disableZooming: nonInteractive,
    labelOverlay: initialMapTypeId === 'satellite' ? 0 : 1, // 0 = 'hidden', 1 = 'visible'
    liteMode: true,
    maxBounds: bounds,
    maxZoom: normalizedMaxZoom,
    minZoom: normalizedMinZoom,
    navigationBarMode: 3, // 3 = square
    showScalebar: false,
    zoom: initialZoom,
  }
}

function addTouchEventListeners({ touchHandlers }) {
  window.addEventListener('touchstart', touchHandlers.touchstartHandler, { passive: false })
  window.addEventListener('touchmove', touchHandlers.touchmoveHandler, { passive: false })
  window.addEventListener('touchend', touchHandlers.touchendHandler, { passive: false })
}

function addMouseEventListeners({
  ctrlKeydownRef,
  newMap,
  nonInteractiveRef,
  parentScrollsRef,
  setShowScrollInstructions,
  wheelDeltaAccumulatorRef,
  wheelZoomDebounceTimeoutRef,
}) {
  let scrollInstructionsTimeout

  // Note: We may want to consider allowing pinch-zoom similar to Google Maps.
  const mousewheelListener = window.Microsoft.Maps.Events.addHandler(newMap, 'mousewheel', () => {
    if (!nonInteractiveRef.current && parentScrollsRef.current && !ctrlKeydownRef.current) {
      setShowScrollInstructions(true)

      clearTimeout(scrollInstructionsTimeout)
      scrollInstructionsTimeout = setTimeout(() => {
        setShowScrollInstructions(false)
      }, SCROLL_INSTRUCTIONS_TIMEOUT_MS)
    }
  })

  const wheelListener = createWheelHandler({
    nonInteractiveRef,
    parentScrollsRef,
    ctrlKeydownRef,
    wheelDeltaAccumulatorRef,
    wheelZoomDebounceTimeoutRef,
    newMap,
  })

  const mapContainer = newMap.getRootElement()
  mapContainer.addEventListener('wheel', wheelListener, false)

  const mouseDownListener = window.Microsoft.Maps.Events.addHandler(newMap, 'mousedown', () => {
    if (!nonInteractiveRef.current) {
      mapContainer.classList.add(draggingCursorClassName)
    }
  })

  const mouseUpListener = window.Microsoft.Maps.Events.addHandler(newMap, 'mouseup', () => {
    mapContainer.classList.remove(draggingCursorClassName)
  })

  return { mouseDownListener, mouseUpListener, mousewheelListener, wheelListener }
}

function handleMapReady({
  ctrlKeydownRef,
  fullscreenControlRef,
  initialOptionsRef,
  isMountedRef,
  isPrimarilyTouchscreen,
  mapRef,
  mapTypeControlRef,
  nonInteractiveRef,
  parentScrollsRef,
  resetViewControlRef,
  setLoading,
  setMap,
  setShowScrollInstructions,
  sharedPopperRef,
  userLocationControlRef,
  wheelDeltaAccumulatorRef,
  wheelZoomDebounceTimeoutRef,
}) {
  const mapOptions = initialOptionsRef.current.mapOptions
  const onChange = initialOptionsRef.current.onChange
  const onReady = initialOptionsRef.current.onReady

  if (mapOptions.maxBounds?.north) {
    mapOptions.maxBounds = window.Microsoft.Maps.LocationRect.fromEdges(
      mapOptions.maxBounds.north,
      mapOptions.maxBounds.west,
      mapOptions.maxBounds.south,
      mapOptions.maxBounds.east
    )
  } else {
    mapOptions.maxBounds = null
  }

  const newMap = new window.Microsoft.Maps.Map(mapRef.current, {
    ...mapOptions,
    disableZooming: false, // See note below
  })

  let touchHandlers
  let mouseListeners
  let isInitialLoad = true

  const viewRenderedHandler = () => {
    // Bing Maps will not show the zoom control if disableZooming is set
    // to true on the initial creation and then later changed to false.
    // This workaround allows us to always initialize with false but then
    // change to true right after if needed.
    if (mapOptions.disableZooming === true) {
      newMap.setOptions({ disableZooming: true })
    }

    setupMapControls({ fullscreenControlRef, mapTypeControlRef, resetViewControlRef, userLocationControlRef })

    // Handle touch device scrolling when clicking on the map
    // https://samples.azuremaps.com/index.htm --> Limit Map to Two Finger Panning
    if (isPrimarilyTouchscreen) {
      touchHandlers = createTouchHandlers({
        mapContainer: mapRef.current,
        setShowScrollInstructions,
        nonInteractiveRef,
        newMap,
      })

      addTouchEventListeners({ touchHandlers })
    } else {
      mouseListeners = addMouseEventListeners({
        newMap,
        nonInteractiveRef,
        parentScrollsRef,
        ctrlKeydownRef,
        setShowScrollInstructions,
        wheelDeltaAccumulatorRef,
        wheelZoomDebounceTimeoutRef,
      })
    }

    // Only update state if component is still mounted
    if (isMountedRef.current) {
      setMap(newMap)
      setLoading(false)

      // Only call onChange/onReady on the initial load, not on subsequent view changes
      if (isInitialLoad) {
        isInitialLoad = false
        onChange?.({ closeOverlay: () => sharedPopperRef.current?.closeOverlay?.() })
        onReady?.()
      }
    }
  }

  return { newMap, touchHandlers, mouseListeners, viewRenderedHandler }
}

function cleanupEventListeners({ mouseListeners, newMap, touchHandlers }) {
  if (touchHandlers) {
    window.removeEventListener('touchend', touchHandlers.touchendHandler)
    window.removeEventListener('touchmove', touchHandlers.touchmoveHandler)
    window.removeEventListener('touchstart', touchHandlers.touchstartHandler)
    touchHandlers.cleanup()
  }

  if (mouseListeners?.mouseDownListener) {
    window.Microsoft?.Maps?.Events?.removeHandler?.(mouseListeners.mouseDownListener)
  }

  if (mouseListeners?.mouseUpListener) {
    window.Microsoft?.Maps?.Events?.removeHandler?.(mouseListeners.mouseUpListener)
  }

  if (mouseListeners?.mousewheelListener) {
    window.Microsoft?.Maps?.Events?.removeHandler?.(mouseListeners.mousewheelListener)
  }

  if (mouseListeners?.wheelListener && newMap) {
    const mapContainer = newMap.getRootElement()
    mapContainer.removeEventListener('wheel', mouseListeners.wheelListener, false)
  }
}

function useMapCreation({
  bounds,
  ctrlKeydownRef,
  fullscreenControlRef,
  initialLatitude,
  initialLongitude,
  initialMapTypeId,
  initialZoom,
  isPrimarilyTouchscreen,
  mapRef,
  mapTypeControlRef,
  maxZoom,
  minZoom,
  nonInteractive,
  nonInteractiveRef,
  onChange,
  onMapApiReadyCallbackName,
  onReady,
  parentScrolls,
  parentScrollsRef,
  resetViewControlRef,
  setLoading,
  setMap,
  setShowScrollInstructions,
  sharedPopperRef,
  shouldUseBing,
  userLocationControlRef,
  wheelDeltaAccumulatorRef,
  wheelZoomDebounceTimeoutRef,
}) {
  const mapCreatedRef = useRef()
  const initialOptionsRef = useRef()
  const isMountedRef = useRef(true)

  if (!initialOptionsRef.current) {
    initialOptionsRef.current = {
      mapOptions: createMapOptions({
        bounds,
        initialLatitude,
        initialLongitude,
        initialMapTypeId,
        initialZoom,
        maxZoom,
        minZoom,
        nonInteractive,
        parentScrolls,
      }),
      onChange,
      onReady,
    }
  }

  // Load the Bing Maps API and create the map
  useEffect(() => {
    let newMap
    let touchHandlers
    let mouseListeners
    let viewRenderedListener

    if (!mapCreatedRef.current) {
      mapCreatedRef.current = true
      setLoading(true)

      const language = getMapLanguage(shouldUseBing)
      const mapSource = `${MAP_API_BASE_URL}?key=${BING_MAPS_API_KEY}&callback=${onMapApiReadyCallbackName}&setLang=${language}`

      window[onMapApiReadyCallbackName] = () => {
        delete window[onMapApiReadyCallbackName]

        const mapHandlers = handleMapReady({
          ctrlKeydownRef,
          fullscreenControlRef,
          initialOptionsRef,
          isMountedRef,
          isPrimarilyTouchscreen,
          mapRef,
          mapTypeControlRef,
          nonInteractiveRef,
          parentScrollsRef,
          resetViewControlRef,
          setLoading,
          setMap,
          setShowScrollInstructions,
          sharedPopperRef,
          userLocationControlRef,
          wheelDeltaAccumulatorRef,
          wheelZoomDebounceTimeoutRef,
        })

        newMap = mapHandlers.newMap
        touchHandlers = mapHandlers.touchHandlers
        mouseListeners = mapHandlers.mouseListeners

        function onRequestAnimationFrame() {
          viewRenderedListener = window.Microsoft.Maps.Events.addHandler(
            newMap,
            'viewrendered',
            mapHandlers.viewRenderedHandler
          )
        }

        requestAnimationFrame(onRequestAnimationFrame)
      }

      const scriptElement = document.createElement('script')
      scriptElement.setAttribute('src', mapSource)
      scriptElement.async = true
      scriptElement.defer = true
      document.body.appendChild(scriptElement)
    }

    return () => {
      isMountedRef.current = false

      cleanupEventListeners({ touchHandlers, mouseListeners, newMap })

      if (newMap && viewRenderedListener) {
        window.Microsoft?.Maps?.Events?.removeHandler?.(viewRenderedListener)
      }

      if (window[onMapApiReadyCallbackName]) {
        delete window[onMapApiReadyCallbackName]
      }

      mapCreatedRef.current = null
    }
  }, [
    ctrlKeydownRef,
    fullscreenControlRef,
    isPrimarilyTouchscreen,
    mapRef,
    mapTypeControlRef,
    nonInteractiveRef,
    onMapApiReadyCallbackName,
    parentScrollsRef,
    resetViewControlRef,
    setLoading,
    setMap,
    setShowScrollInstructions,
    sharedPopperRef,
    shouldUseBing,
    userLocationControlRef,
    wheelDeltaAccumulatorRef,
    wheelZoomDebounceTimeoutRef,
  ])
}

function useBoundsChangedListener({ map, onBoundsChanged, onBoundsChangedCallbacksRef }) {
  const boundsChanged = useCallback(() => {
    if (!map) return

    const currentBounds = map.getBounds()
    const currentZoom = map.getZoom()

    const args = {
      center: currentBounds.center,
      east: currentBounds.bounds[1],
      north: currentBounds.bounds[0],
      south: currentBounds.bounds[2],
      west: currentBounds.bounds[3],
      zoom: currentZoom,
    }

    onBoundsChangedCallbacksRef.current.forEach(({ callback }) => callback(args))
    onBoundsChanged?.(args)
  }, [map, onBoundsChanged, onBoundsChangedCallbacksRef])

  // Listen for bounds changes
  useEffect(() => {
    let boundsChangedListener

    if (map && (typeof onBoundsChanged === 'function' || onBoundsChangedCallbacksRef.current.length > 0)) {
      boundsChangedListener = window.Microsoft.Maps.Events.addThrottledHandler(
        map,
        'viewchangeend',
        boundsChanged,
        BOUNDS_CHANGED_THROTTLE_DELAY_MS
      )
    }

    return () => {
      if (boundsChangedListener) {
        window.Microsoft?.Maps?.Events?.removeHandler?.(boundsChangedListener)
      }
    }
  }, [boundsChanged, map, onBoundsChanged, onBoundsChangedCallbacksRef])
}

function useZoomChangedListener({ map, onZoomChangedCallbacksRef }) {
  const previousZoomRef = useRef(null)

  const zoomChanged = useCallback(() => {
    if (!map || onZoomChangedCallbacksRef.current.length === 0) {
      return
    }

    const currentZoom = map.getZoom()

    // Only proceed if the zoom level has actually changed
    if (previousZoomRef.current !== null && previousZoomRef.current === currentZoom) {
      return
    }

    // Update the previous zoom reference
    previousZoomRef.current = currentZoom

    const currentBounds = map.getBounds()

    const args = {
      center: currentBounds.center,
      east: currentBounds.bounds[1],
      north: currentBounds.bounds[0],
      south: currentBounds.bounds[2],
      west: currentBounds.bounds[3],
      zoom: currentZoom,
    }

    onZoomChangedCallbacksRef.current.forEach(({ callback }) => callback(args))
  }, [map, onZoomChangedCallbacksRef])

  // Listen for zoom changes
  useEffect(() => {
    let zoomChangedListener

    if (map) {
      // Initialize the previous zoom value when setting up the listener
      previousZoomRef.current = map.getZoom()

      zoomChangedListener = window.Microsoft.Maps.Events.addThrottledHandler(
        map,
        'viewchangeend',
        zoomChanged,
        BOUNDS_CHANGED_THROTTLE_DELAY_MS
      )
    }
    return () => {
      if (zoomChangedListener) {
        window.Microsoft?.Maps?.Events?.removeHandler?.(zoomChangedListener)
      }
    }
  }, [map, onZoomChangedCallbacksRef, zoomChanged])
}

function useMapClickListener({ map, onClick, skipNextClickRef }) {
  const onClickRef = useRef(onClick)
  const clickTimerRef = useRef(null)

  useEffect(() => {
    onClickRef.current = onClick
  }, [onClick])

  useEffect(() => {
    if (!map) {
      return undefined
    }

    // Ignore double clicks
    const doubleClickListener = window.Microsoft.Maps.Events.addHandler(map, 'dblclick', () => {
      // Clear any pending single click
      if (clickTimerRef.current) {
        clearTimeout(clickTimerRef.current)
        clickTimerRef.current = null
      }
    })

    const clickHandler = (event) => {
      if (skipNextClickRef.current) {
        skipNextClickRef.current = false
        return
      }

      // Delay single click to wait for potential double click
      clickTimerRef.current = setTimeout(() => {
        if (onClickRef.current) {
          onClickRef.current({
            position: {
              latitude: event.location.latitude,
              longitude: event.location.longitude,
            },
          })
        }

        clickTimerRef.current = null
      }, DOUBLE_CLICK_DELAY)
    }

    const clickListener = window.Microsoft.Maps.Events.addHandler(map, 'click', clickHandler)

    return () => {
      if (clickTimerRef.current) {
        clearTimeout(clickTimerRef.current)
      }

      window.Microsoft?.Maps?.Events?.removeHandler?.(clickListener)
      window.Microsoft?.Maps?.Events?.removeHandler?.(doubleClickListener)
    }
  }, [map, skipNextClickRef])
}

function useMapOptions({ map, nonInteractive, nonInteractiveRef, options, parentScrolls, parentScrollsRef }) {
  // Update the map view and options when they change
  useEffect(() => {
    if (map) {
      if (options.maxBounds?.north) {
        options.maxBounds = window.Microsoft.Maps.LocationRect.fromEdges(
          options.maxBounds.north,
          options.maxBounds.west,
          options.maxBounds.south,
          options.maxBounds.east
        )
      } else {
        options.maxBounds = null
      }

      nonInteractiveRef.current = nonInteractive
      parentScrollsRef.current = parentScrolls

      map.setView({
        center: options.center,
        labelOverlay: options.labelOverlay,
        zoom: options.zoom,
      })

      map.setOptions({
        backgroundColor: options.backgroundColor,
        disableBirdseye: options.disableBirdseye,
        disableKeyboardInput: options.disableKeyboardInput,
        disablePanning: options.disablePanning,
        disableScrollWheelZoom: options.disableScrollWheelZoom,
        disableZooming: options.disableZooming,
        liteMode: options.liteMode,
        maxBounds: options.maxBounds,
        maxZoom: options.maxZoom,
        minZoom: options.minZoom,
        navigationBarMode: options.navigationBarMode,
        showScalebar: options.showScalebar,
      })
    }
  }, [map, nonInteractive, nonInteractiveRef, options, parentScrolls, parentScrollsRef])
}

function useMapViewFitting({ childrenBounds, childrenBoundsApi, map, options }) {
  // Fit the map to the children bounds or center on the initial location.
  useEffect(() => {
    if (!map) {
      return
    }

    if (childrenBoundsApi.skipNextFitToChildrenRef.current) {
      childrenBoundsApi.skipNextFitToChildrenRef.current = false
      return
    }

    if (childrenBounds.bounds) {
      // We may want to consider only running this if the user has
      // not changed the map bounds from the initial bounds.
      const boundingBox = window.Microsoft.Maps.LocationRect.fromEdges(
        childrenBounds.bounds.north,
        childrenBounds.bounds.west,
        childrenBounds.bounds.south,
        childrenBounds.bounds.east
      )

      const boundsOptions = {
        bounds: boundingBox,
        center: boundingBox.center,
        padding: LARGEST_MARKER_SIZE_PX,
      }

      map.setView(boundsOptions)
    } else if (childrenBounds.optimalZoom !== undefined && childrenBounds.centroidLocation) {
      map.setView({
        center: childrenBounds.centroidLocation,
        zoom: childrenBounds.optimalZoom,
      })
    } else {
      map.setView({
        center: options.center,
        zoom: options.zoom,
      })
    }
  }, [childrenBounds, childrenBoundsApi, map, options])
}

function useScrollZoomInteraction({ ctrlKeydownRef, map, nonInteractive, parentScrolls, setShowScrollInstructions }) {
  // Setup scroll zoom interaction
  useEffect(() => {
    if (!map) return undefined

    function keydownListener({ ctrlKey }) {
      if (ctrlKey) {
        ctrlKeydownRef.current = true
        setShowScrollInstructions(false)
        map.setOptions({ disableScrollWheelZoom: false })
      }
    }

    function keyupListener({ ctrlKey }) {
      if (!ctrlKey) {
        ctrlKeydownRef.current = false
        map.setOptions({ disableScrollWheelZoom: nonInteractive || parentScrolls })
      }
    }

    window.parent.addEventListener('keydown', keydownListener)
    window.parent.addEventListener('keyup', keyupListener)
    window.addEventListener('keydown', keydownListener)
    window.addEventListener('keyup', keyupListener)

    return () => {
      window.parent.removeEventListener('keydown', keydownListener)
      window.parent.removeEventListener('keyup', keyupListener)
      window.removeEventListener('keydown', keydownListener)
      window.removeEventListener('keyup', keyupListener)
    }
  }, [map, nonInteractive, parentScrolls, ctrlKeydownRef, setShowScrollInstructions])
}

const BingMap = forwardRef(
  (
    {
      bounds,
      children,
      hideFullscreenControl,
      hideMapTypeControl,
      initialLatitude,
      initialLongitude,
      initialMapTypeId,
      initialZoom,
      maxZoom,
      minZoom,
      nonInteractive,
      onBoundsChanged,
      onChange,
      onClick,
      onInfoClosed,
      onReady,
      parentScrolls,
      shouldUseBing,
      testId = 'bing-map',
      userLocation,
    },
    ref
  ) => {
    const mapRef = useRef()
    const [map, setMap] = useState()
    const [loading, setLoading] = useState(true)
    const childrenBounds = useChildrenBounds()
    const childrenBoundsApi = useChildrenBoundsApi()
    const onMapApiReadyCallbackName = useRandomId()
    const fullscreenControlRef = useRef()
    const mapTypeControlRef = useRef()
    const resetViewControlRef = useRef()
    const userLocationControlRef = useRef()
    const [showScrollInstructions, setShowScrollInstructions] = useState(false)
    const ctrlKeydownRef = useRef(false)
    const onBoundsChangedCallbacksRef = useRef([])
    const onZoomChangedCallbacksRef = useRef([])
    const wheelZoomDebounceTimeoutRef = useRef()
    const wheelDeltaAccumulatorRef = useRef(0)
    const nonInteractiveRef = useRef(nonInteractive)
    const parentScrollsRef = useRef(parentScrolls)
    const popperUpdateHandlerListenersRef = useRef([])
    const fullscreenContainerRef = useRef()
    const sharedPopperRef = useRef()
    const skipNextClickRef = useRef(false)

    useImperativeHandle(
      ref,
      () => ({
        closeOverlay: () => sharedPopperRef.current?.closeOverlay?.(),
      }),
      []
    )

    const isPrimarilyTouchscreen = typeof window !== 'undefined' && window.matchMedia('(pointer: coarse)').matches

    createElementIfNeeded({ ref: fullscreenControlRef })
    createElementIfNeeded({ ref: mapTypeControlRef })
    createElementIfNeeded({ ref: resetViewControlRef })
    createElementIfNeeded({ ref: userLocationControlRef })

    const options = useMemo(
      () =>
        createMapOptions({
          bounds,
          initialLatitude,
          initialLongitude,
          initialMapTypeId,
          initialZoom,
          maxZoom,
          minZoom,
          nonInteractive,
          parentScrolls,
        }),
      [
        bounds,
        initialLatitude,
        initialLongitude,
        initialMapTypeId,
        initialZoom,
        maxZoom,
        minZoom,
        nonInteractive,
        parentScrolls,
      ]
    )

    useMapCreation({
      bounds,
      ctrlKeydownRef,
      fullscreenControlRef,
      initialLatitude,
      initialLongitude,
      initialMapTypeId,
      initialZoom,
      isPrimarilyTouchscreen,
      mapRef,
      mapTypeControlRef,
      maxZoom,
      minZoom,
      nonInteractive,
      nonInteractiveRef,
      onChange,
      onMapApiReadyCallbackName,
      onReady,
      parentScrolls,
      parentScrollsRef,
      resetViewControlRef,
      setLoading,
      setMap,
      setShowScrollInstructions,
      sharedPopperRef,
      shouldUseBing,
      userLocationControlRef,
      wheelDeltaAccumulatorRef,
      wheelZoomDebounceTimeoutRef,
    })

    useBoundsChangedListener({ map, onBoundsChanged, onBoundsChangedCallbacksRef })
    useZoomChangedListener({ map, onZoomChangedCallbacksRef })
    useMapClickListener({ map, onClick, skipNextClickRef })
    // NOTE: This must come before `useMapViewFitting` in order for the children bounds to work correctly.
    useMapOptions({ map, nonInteractive, nonInteractiveRef, options, parentScrolls, parentScrollsRef })
    // NOTE: This must come after `useMapOptions` in order for the options to be set correctly.
    useMapViewFitting({ childrenBounds, childrenBoundsApi, map, options })
    useScrollZoomInteraction({ ctrlKeydownRef, map, nonInteractive, parentScrolls, setShowScrollInstructions })

    const getCurrentZoom = useCallback(() => {
      if (!map) {
        return null
      }

      return map.getZoom()
    }, [map])

    const onBoundsChangedAdd = useCallback(
      ({ id, callback }) => {
        onBoundsChangedCallbacksRef.current.push({ id, callback })

        if (map) {
          const currentBounds = map.getBounds()

          callback({
            center: map.getCenter(),
            east: currentBounds.bounds[1],
            north: currentBounds.bounds[0],
            south: currentBounds.bounds[2],
            west: currentBounds.bounds[3],
            zoom: map.getZoom(),
          })
        }
      },
      [map]
    )

    const onBoundsChangedRemove = useCallback(({ id }) => {
      onBoundsChangedCallbacksRef.current = onBoundsChangedCallbacksRef.current.filter(
        ({ id: currentId }) => currentId !== id
      )
    }, [])

    const onBoundsChangedMemo = useMemo(
      () => ({
        add: onBoundsChangedAdd,
        remove: onBoundsChangedRemove,
      }),
      [onBoundsChangedAdd, onBoundsChangedRemove]
    )

    const onZoomChangedAdd = useCallback(({ callback, id }) => {
      onZoomChangedCallbacksRef.current.push({ callback, id })
    }, [])

    const onZoomChangedRemove = useCallback(({ id }) => {
      onZoomChangedCallbacksRef.current = onZoomChangedCallbacksRef.current.filter(
        ({ id: currentId }) => currentId !== id
      )
    }, [])

    const onZoomChangedMemo = useMemo(
      () => ({
        add: onZoomChangedAdd,
        remove: onZoomChangedRemove,
      }),
      [onZoomChangedAdd, onZoomChangedRemove]
    )

    const whenIdle = useCallback(({ callback }) => {
      return new Promise((resolve) => {
        // Animation frame is needed to ensure the map is fully idle
        requestAnimationFrame(() => {
          callback()
          resolve()
        })
      })
    }, [])

    const zoomPan = useCallback(
      ({ bounds: zoomPanBounds, latitude, longitude, zoom }) => {
        if (!map) {
          return
        }

        const viewOptions = {}

        if (zoomPanBounds) {
          const boundingBox = window.Microsoft.Maps.LocationRect.fromEdges(
            zoomPanBounds.north,
            zoomPanBounds.west,
            zoomPanBounds.south,
            zoomPanBounds.east
          )

          viewOptions.bounds = boundingBox
          viewOptions.center = boundingBox.center
          viewOptions.padding = LARGEST_MARKER_SIZE_PX
        } else if (zoom) {
          viewOptions.zoom = zoom
        }

        if (
          typeof latitude === 'number' &&
          !Number.isNaN(latitude) &&
          typeof longitude === 'number' &&
          !Number.isNaN(longitude)
        ) {
          viewOptions.center = {
            latitude,
            longitude,
          }
        }

        map.setView(viewOptions)
      },
      [map]
    )

    const updateHandlerAdd = useCallback(
      (callback) => {
        if (!map) {
          return
        }

        popperUpdateHandlerListenersRef.current.push(
          window.Microsoft.Maps.Events.addHandler(map, 'viewchange', callback),
          window.Microsoft.Maps.Events.addHandler(map, 'viewchangeend', callback),
          window.Microsoft.Maps.Events.addHandler(map, 'viewrendered', callback)
        )
      },
      [map]
    )

    const updateHandlerRemove = useCallback(() => {
      popperUpdateHandlerListenersRef.current.forEach((listener) => {
        window.Microsoft?.Maps?.Events?.removeHandler?.(listener)
      })

      popperUpdateHandlerListenersRef.current = []
    }, [])

    const updateHandlerMemo = useMemo(
      () => ({
        add: updateHandlerAdd,
        remove: updateHandlerRemove,
      }),
      [updateHandlerAdd, updateHandlerRemove]
    )

    const mapCursor = useMemo(() => {
      let cursor = nonInteractive ? 'default' : 'grab'

      if (onClick) {
        cursor = nonInteractive ? 'default' : 'pointer'
      }

      return cursor
    }, [nonInteractive, onClick])

    return (
      <div className={mapContainerClassName} ref={fullscreenContainerRef}>
        {loading && (
          <Center>
            <NoticeLoading color={rawDayColors.gray[100]} size="lg" />
          </Center>
        )}
        <div className={cx(scrollClassName, !nonInteractive && showScrollInstructions && scrollShowClassName)}>
          {isPrimarilyTouchscreen
            ? i18n.t('map.map.touch', 'Use two fingers to move the map')
            : i18n.t('map.map.scroll', 'Use ctrl + scroll to zoom in and out.')}
        </div>
        <div
          className={mapClassName}
          data-testid={testId}
          ref={mapRef}
          style={{
            '--map-cursor': mapCursor,
            '--zoom-control-display': nonInteractive ? 'none' : 'block',
          }}
        />
        <MapProvider
          bing
          fullscreenContainer={fullscreenContainerRef.current}
          getCurrentZoom={getCurrentZoom}
          initialLatitude={initialLatitude}
          initialLongitude={initialLongitude}
          initialZoom={initialZoom}
          map={map}
          mapContainer={mapRef}
          maxZoom={options.maxZoom} // Contains the normalized max zoom level
          nonInteractive={nonInteractive}
          onBoundsChanged={onBoundsChangedMemo}
          onZoomChanged={onZoomChangedMemo}
          skipNextClickRef={skipNextClickRef}
          whenIdle={whenIdle}
          zoomPan={zoomPan}
        >
          <SharedPopperProvider onInfoClosed={onInfoClosed} updateHandler={updateHandlerMemo} ref={sharedPopperRef}>
            {/* createPortal used to preserve the correct tab order for A11Y */}
            {userLocation && <>{createPortal(<UserLocationControl />, userLocationControlRef.current)}</>}
            <>{createPortal(<ResetViewControl />, resetViewControlRef.current)}</>
            {children}
          </SharedPopperProvider>
          {!hideFullscreenControl && !isPrimarilyTouchscreen && (
            <>{createPortal(<FullscreenControl bing />, fullscreenControlRef.current)}</>
          )}
          {!hideMapTypeControl && (
            <>{createPortal(<MapTypeControl initialMapTypeId={initialMapTypeId} />, mapTypeControlRef.current)}</>
          )}
        </MapProvider>
      </div>
    )
  }
)

BingMap.displayName = 'BingMap'

export default BingMap

BingMap.propTypes = {
  bounds: PropTypes.shape({
    east: PropTypes.number.isRequired,
    north: PropTypes.number.isRequired,
    south: PropTypes.number.isRequired,
    west: PropTypes.number.isRequired,
  }),
  children: PropTypes.node,
  hideFullscreenControl: PropTypes.bool,
  hideMapTypeControl: PropTypes.bool,
  initialLatitude: PropTypes.number.isRequired,
  initialLongitude: PropTypes.number.isRequired,
  initialMapTypeId: PropTypes.string,
  initialZoom: PropTypes.number,
  maxZoom: PropTypes.number,
  minZoom: PropTypes.number,
  nonInteractive: PropTypes.bool,
  onBoundsChanged: PropTypes.func,
  onChange: PropTypes.func,
  onClick: PropTypes.func,
  onInfoClosed: PropTypes.func,
  onReady: PropTypes.func,
  parentScrolls: PropTypes.bool,
  shouldUseBing: PropTypes.bool,
  testId: PropTypes.string,
  userLocation: PropTypes.bool,
}
