import React, { useEffect, useState } from 'react'
import { i18n } from '@fs/zion-locale'
import { Button, Checkbox, ListItem, MenuOverlay, Row } from '@fs/zion-ui'

import useMap from '../../shared/hooks/useMap'
import menuClassName from '../../shared/controls/menuClassName'

const MAP_TYPE_IDS = {
  blank: 'm',
  hybrid: 'a',
  roadmap: 'r',
  satellite: 'a',
  terrain: 'r',
}

export default function MapTypeControl({ initialMapTypeId = 'roadmap' }) {
  const { map, nonInteractive } = useMap()
  const [mapTypeId, setMapTypeId] = useState(MAP_TYPE_IDS.roadmap)
  const [showLabels, setShowLabels] = useState(true)

  useEffect(() => {
    if (map) {
      const convertedInitialMapTypeId = MAP_TYPE_IDS[initialMapTypeId] || MAP_TYPE_IDS.roadmap

      try {
        setMapTypeId(convertedInitialMapTypeId)
        setShowLabels(initialMapTypeId !== 'satellite')

        map.setView({
          mapTypeId: convertedInitialMapTypeId,
          labelOverlay: initialMapTypeId !== 'satellite' ? 1 : 0, // 0 = 'hidden', 1 = 'visible'
        })
      } catch (error) {
        setMapTypeId(MAP_TYPE_IDS.roadmap)
        setShowLabels(true)

        map.setView({ mapTypeId: MAP_TYPE_IDS.roadmap, labelOverlay: 1 }) // 0 = 'hidden', 1 = 'visible'
      }
    }
  }, [initialMapTypeId, map])

  if (nonInteractive || mapTypeId === MAP_TYPE_IDS.blank) {
    return null
  }

  let index = mapTypeId === MAP_TYPE_IDS.roadmap || mapTypeId === MAP_TYPE_IDS.terrain ? 1 : 2
  if (mapTypeId === MAP_TYPE_IDS.blank) {
    index = 0
  }

  return (
    <Row className={menuClassName} data-selected-button-index={index} guttersX="none">
      <MenuOverlay
        aria-label={i18n.t('map.map-type-control.street', 'Show street map')}
        menuButton={
          <Button title={i18n.t('map.map-type-control.street', 'Show street map')}>
            {i18n.t('map.map-type-control.map', 'Map')}
          </Button>
        }
        onClick={() => {
          map.setView({ mapTypeId: MAP_TYPE_IDS.roadmap, labelOverlay: 1 }) // 0 = 'hidden', 1 = 'visible'
          setMapTypeId(MAP_TYPE_IDS.roadmap)
        }}
      />
      <MenuOverlay
        aria-label={i18n.t('map.map-type-control.imagery', 'Show satellite imagery')}
        menuButton={
          <Button title={i18n.t('map.map-type-control.imagery', 'Show satellite imagery')}>
            {i18n.t('map.map-type-control.satellite', 'Satellite')}
          </Button>
        }
        onClick={() => {
          try {
            if (showLabels) {
              map.setView({ mapTypeId: MAP_TYPE_IDS.hybrid, labelOverlay: 1 }) // 0 = 'hidden', 1 = 'visible'
              setMapTypeId(MAP_TYPE_IDS.hybrid)
            } else {
              map.setView({ mapTypeId: MAP_TYPE_IDS.satellite, labelOverlay: 0 }) // 0 = 'hidden', 1 = 'visible'
              setMapTypeId(MAP_TYPE_IDS.satellite)
            }
          } catch (error) {
            map.setView({ mapTypeId: MAP_TYPE_IDS.roadmap, labelOverlay: 1 }) // 0 = 'hidden', 1 = 'visible'
            setMapTypeId(MAP_TYPE_IDS.roadmap)
          }
        }}
      >
        <ListItem
          onClick={(event) => {
            event.stopPropagation()

            try {
              if (showLabels) {
                map.setView({ mapTypeId: MAP_TYPE_IDS.satellite, labelOverlay: 0 }) // 0 = 'hidden', 1 = 'visible'
                setMapTypeId(MAP_TYPE_IDS.satellite)
              } else {
                map.setView({ mapTypeId: MAP_TYPE_IDS.hybrid, labelOverlay: 1 }) // 0 = 'hidden', 1 = 'visible'
                setMapTypeId(MAP_TYPE_IDS.hybrid)
              }
            } catch (error) {
              map.setView({ mapTypeId: MAP_TYPE_IDS.roadmap, labelOverlay: 1 }) // 0 = 'hidden', 1 = 'visible'
              setMapTypeId(MAP_TYPE_IDS.roadmap)
            }

            setShowLabels(!showLabels)
          }}
          primaryText={i18n.t('map.map-type-control.labels', 'Labels')}
          startElement={
            <Checkbox
              checked={showLabels}
              aria-label={i18n.t('map.map-type-control.labels', 'Labels')}
              name={i18n.t('map.map-type-control.labels', 'Labels')}
              onChange={() => {
                // The onChange handler is required but we do not need to do anything here.
              }}
            />
          }
          title={i18n.t('map.map-type-control.imagery-names', 'Show imagery with street names')}
        />
      </MenuOverlay>
    </Row>
  )
}
